const { items, count, skip_processing } = $input.first().json;
if (skip_processing || !items.length) {
  return [{ json: { skip: true, reason: 'No items to process' } }];
}

// Build prompt for AI clustering
const itemList = items.map((item, i) => {
  const cats = item.category_tags.join(', ');
  const tags = item.ai_tags.join(', ');
  return `[${i}] "${item.title}" (${item.source_name || item.origin}) — Categories: ${cats} — Tags: ${tags} — ${item.summary?.substring(0, 150) || ''}`;
}).join('\n');

const prompt = `You are an intelligence analyst for T-0, a company building AI agent infrastructure. Analyze these ${count} collected items and create a weekly intelligence digest.

ITEMS:
${itemList}

TASK:
1. Group these items into 3-8 topic clusters based on thematic similarity
2. For each cluster, provide:
   - A clear, specific title (not generic like "AI News")
   - A 2-3 sentence summary of the cluster theme
   - Which item indices belong to this cluster (use [N] format)
   - A relevance assessment: why this matters for T-0
   - A suggested content angle for a blog post

3. Identify 1-3 "Signals to Watch" — items that don't fit clusters but are individually noteworthy

4. Write a 2-3 paragraph executive summary of the week's intelligence

IMPORTANT:
- Focus on what matters for T-0: AI agents, automation, MCP protocol, enterprise AI, developer tools, German AI market
- Every item must be assigned to exactly one cluster OR listed as a signal
- Be specific in content angles — "write about X" not "consider writing about Y"

OUTPUT FORMAT (JSON):
{
  "executive_summary": "...",
  "clusters": [
    {
      "title": "...",
      "summary": "...",
      "item_indices": [0, 3, 7],
      "relevance": "...",
      "content_angle": "..."
    }
  ],
  "signals": [
    {
      "item_index": 5,
      "note": "..."
    }
  ]
}`;

return [{ json: { prompt, items, count } }];

const items = $('Prepare Clustering').first().json.items;
const count = $('Prepare Clustering').first().json.count;
const aiResp = $input.first().json;

const content = aiResp.choices?.[0]?.message?.content || '{}';
const jsonMatch = content.match(/\{[\s\S]*\}/);
let digest;
try {
  digest = JSON.parse(jsonMatch ? jsonMatch[0] : content);
} catch(e) {
  return [{ json: { error: 'Failed to parse AI response: ' + e.message, raw: content.substring(0, 500) } }];
}

// Build week number
const now = new Date();
const startOfYear = new Date(now.getFullYear(), 0, 1);
const weekNum = Math.ceil(((now - startOfYear) / 86400000 + startOfYear.getDay() + 1) / 7);

// Build report body as markdown
let body = `## Summary\n\n${digest.executive_summary || 'No summary generated.'}\n\n`;
body += `## Topic Clusters\n\n`;

const clusters = digest.clusters || [];
for (let ci = 0; ci < clusters.length; ci++) {
  const c = clusters[ci];
  const clusterItems = (c.item_indices || []).map(idx => items[idx]).filter(Boolean);
  body += `### ${ci + 1}. ${c.title} (${clusterItems.length} items)\n`;
  body += `**Relevance**: ${c.relevance || 'N/A'}\n`;
  body += `**Content Angle**: ${c.content_angle || 'N/A'}\n`;
  body += `**Items**:\n`;
  for (const item of clusterItems) {
    const date = item.time ? item.time.split('T')[0] : 'N/A';
    body += `- ${item.title} — ${item.source_name || item.origin} — ${date}\n`;
  }
  body += `\n`;
}

const signals = digest.signals || [];
if (signals.length) {
  body += `## Signals to Watch\n\n`;
  for (const s of signals) {
    const item = items[s.item_index];
    if (item) {
      body += `- **${item.title}** (${item.source_name || item.origin}): ${s.note || ''}\n`;
    }
  }
  body += `\n`;
}

body += `## Recommended Actions\n\n`;
for (let ci = 0; ci < clusters.length; ci++) {
  const c = clusters[ci];
  if (c.content_angle) {
    body += `- [ ] Write post about "${c.title}" — angle: ${c.content_angle}\n`;
  }
}
for (const s of signals) {
  const item = items[s.item_index];
  if (item) {
    body += `- [ ] Monitor: ${item.title}\n`;
  }
}

// Collect all note page IDs for the relation
const notePageIds = items.map(i => i.page_id);

// Date range for the Time property
const oldest = items.length ? items[items.length - 1].time : now.toISOString();
const newest = items.length ? items[0].time : now.toISOString();

// Build the report creation request body
const reportBody = {
  parent: { database_id: '2e8c0fdf-942d-8059-8aaa-d2fb0f6f3a4b' },
  properties: {
    'Name': { title: [{ text: { content: `Content Intelligence — KW ${weekNum} ${now.getFullYear()}` } }] },
    'Time': { date: { start: oldest.split('T')[0], end: newest.split('T')[0] } },
    'Tags': { multi_select: [{ name: 'Content Intelligence' }, { name: 'Weekly Digest' }] },
    'Description': { rich_text: [{ text: { content: (digest.executive_summary || '').substring(0, 2000) } }] },
    'Notes': { relation: notePageIds.slice(0, 100).map(id => ({ id })) },
    'Agent': { multi_select: [{ name: 'n8n Workflow' }] },
    'Model': { multi_select: [{ name: 'Opus 4.6' }] },
  },
};

return [{ json: {
  requestBody: JSON.stringify(reportBody),
  reportBody: body,
  notePageIds,
  noteCount: notePageIds.length,
  clusterCount: clusters.length,
  signalCount: signals.length,
  weekLabel: `KW ${weekNum} ${now.getFullYear()}`,
} }];

const reportBody = $('Parse Clusters & Build Report').first().json.reportBody;
const reportId = $input.first().json.id;

if (!reportId) {
  return [{ json: { error: 'No report ID from Create Report' } }];
}

// Split markdown into blocks for Notion
// Notion API supports: heading_2, heading_3, paragraph, to_do, bulleted_list_item
const lines = reportBody.split('\n');
const children = [];

for (const line of lines) {
  const trimmed = line.trim();
  if (!trimmed) continue;

  if (trimmed.startsWith('## ')) {
    children.push({
      object: 'block',
      type: 'heading_2',
      heading_2: { rich_text: [{ type: 'text', text: { content: trimmed.replace('## ', '') } }] }
    });
  } else if (trimmed.startsWith('### ')) {
    children.push({
      object: 'block',
      type: 'heading_3',
      heading_3: { rich_text: [{ type: 'text', text: { content: trimmed.replace('### ', '') } }] }
    });
  } else if (trimmed.startsWith('- [ ] ')) {
    children.push({
      object: 'block',
      type: 'to_do',
      to_do: { rich_text: [{ type: 'text', text: { content: trimmed.replace('- [ ] ', '') } }], checked: false }
    });
  } else if (trimmed.startsWith('- ')) {
    // Parse bold text
    const text = trimmed.replace('- ', '');
    const parts = [];
    let remaining = text;
    const boldRegex = /\*\*([^*]+)\*\*/g;
    let lastIdx = 0;
    let match;
    while ((match = boldRegex.exec(text)) !== null) {
      if (match.index > lastIdx) {
        parts.push({ type: 'text', text: { content: text.substring(lastIdx, match.index) } });
      }
      parts.push({ type: 'text', text: { content: match[1] }, annotations: { bold: true } });
      lastIdx = match.index + match[0].length;
    }
    if (lastIdx < text.length) {
      parts.push({ type: 'text', text: { content: text.substring(lastIdx) } });
    }
    children.push({
      object: 'block',
      type: 'bulleted_list_item',
      bulleted_list_item: { rich_text: parts.length ? parts : [{ type: 'text', text: { content: text } }] }
    });
  } else if (trimmed.startsWith('**')) {
    // Bold line (like **Relevance**: ...)
    const parts = [];
    const boldRegex = /\*\*([^*]+)\*\*/g;
    let lastIdx = 0;
    let match;
    while ((match = boldRegex.exec(trimmed)) !== null) {
      if (match.index > lastIdx) {
        parts.push({ type: 'text', text: { content: trimmed.substring(lastIdx, match.index) } });
      }
      parts.push({ type: 'text', text: { content: match[1] }, annotations: { bold: true } });
      lastIdx = match.index + match[0].length;
    }
    if (lastIdx < trimmed.length) {
      parts.push({ type: 'text', text: { content: trimmed.substring(lastIdx) } });
    }
    children.push({
      object: 'block',
      type: 'paragraph',
      paragraph: { rich_text: parts }
    });
  } else {
    children.push({
      object: 'block',
      type: 'paragraph',
      paragraph: { rich_text: [{ type: 'text', text: { content: trimmed } }] }
    });
  }
}

// Notion API limits to 100 children per request
const batch = children.slice(0, 100);
const requestBody = JSON.stringify({ children: batch });

return [{ json: { reportId, requestBody, blockCount: batch.length } }];

const notePageIds = $('Parse Clusters & Build Report').first().json.notePageIds;

// Output one item per note to update
const updates = notePageIds.map(id => ({
  json: {
    requestBody: JSON.stringify({
      properties: {
