  const originDesc = (p['Origin Description']?.rich_text || []).map(t => t.plain_text).join('');
  const sourceName = (p['Source']?.relation || []).length > 0 ? originDesc.replace(/ \(.*\)$| RSS$/, '') : '';
  const cats = (p['Category Tags']?.multi_select || []).map(o => o.name);
  const aiTags = (p['AI-Tags']?.multi_select || []).map(o => o.name);
  const status = p['Status']?.status?.name || '';
  return { page_id: page.id, title, url, time, summary: summary || description, origin, origin_description: originDesc, source_name: sourceName, category_tags: cats, ai_tags: aiTags, status };
